import Foundation

struct CategoryContent9 {
    static let aiHistory = CategoryData(
        id: "ai_history", name: "AI History & Pioneers", icon: "clock.arrow.circlepath", colorName: "aiBrown",
        description: "Turing, McCarthy, AI winters, AlphaGo, ChatGPT moment",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 8,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "aih_l1", title: "The Birth of AI", description: "How it all began", categoryId: "ai_history", questions: [
        Question(id: "aih1_q1", type: .multipleChoice, questionText: "The term 'Artificial Intelligence' was coined in:", options: ["1956 at the Dartmouth Conference", "1943 at a wartime research lab", "1969 at the ARPANET launch", "1975 at a Stanford symposium"], correctAnswer: "1956 at the Dartmouth Conference", explanation: "John McCarthy coined the term at the Dartmouth Summer Research Project on AI in 1956, attended by pioneers like Marvin Minsky, Nathaniel Rochester, and Claude Shannon."),
        Question(id: "aih1_q2", type: .trueFalse, questionText: "Alan Turing proposed a test for machine intelligence before the field of AI formally existed.", options: ["True", "False"], correctAnswer: "True", explanation: "Turing published 'Computing Machinery and Intelligence' in 1950, introducing the imitation game six years before AI was established as a field at Dartmouth."),
        Question(id: "aih1_q3", type: .fillInBlank, questionText: "The __________ Test asks whether a machine can exhibit intelligent behavior indistinguishable from a human.", options: ["Turing", "McCarthy", "Shannon", "Minsky"], correctAnswer: "Turing", explanation: "Alan Turing proposed this test in 1950, framing it as the 'imitation game' to evaluate whether machines can think."),
        Question(id: "aih1_q4", type: .sortOrder, questionText: "Order these AI milestones chronologically:", options: ["AI term coined at Dartmouth (1956)", "Expert systems era begins (1980s)", "Turing Test proposed (1950)", "ELIZA chatbot created (1966)"], correctAnswers: ["Turing Test proposed (1950)", "AI term coined at Dartmouth (1956)", "ELIZA chatbot created (1966)", "Expert systems era begins (1980s)"], explanation: "AI progressed from theoretical foundations through formal establishment to early practical systems and commercial applications."),
        Question(id: "aih1_q5", type: .multipleChoice, questionText: "Who organized the 1956 Dartmouth Conference that launched AI as a field?", options: ["John McCarthy", "Alan Turing", "Norbert Wiener", "Claude Shannon"], correctAnswer: "John McCarthy", explanation: "McCarthy organized the Dartmouth Conference and coined the term 'Artificial Intelligence,' establishing it as a distinct field of study."),
        Question(id: "aih1_q6", type: .multipleChoice, questionText: "ELIZA, created by Joseph Weizenbaum at MIT in 1966, was significant because it:", options: ["Was one of the first programs to simulate conversation", "Could accurately translate between languages", "Solved complex mathematical proofs", "Recognized human speech with high accuracy"], correctAnswer: "Was one of the first programs to simulate conversation", explanation: "ELIZA simulated a Rogerian therapist using pattern matching. Many users attributed human-like understanding to it, foreshadowing debates about AI that continue today.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "aih_l2", title: "AI Winters", description: "When AI fell out of favor", categoryId: "ai_history", questions: [
        Question(id: "aih2_q1", type: .multipleChoice, questionText: "An 'AI winter' refers to:", options: ["A period of reduced funding and interest in AI research", "A seasonal slowdown in AI hardware production", "A deliberate pause in AI development for safety", "A period when AI research shifts to colder climates"], correctAnswer: "A period of reduced funding and interest in AI research", explanation: "AI winters were periods when hype exceeded reality, leading governments and corporations to slash funding and researchers to leave the field."),
        Question(id: "aih2_q2", type: .trueFalse, questionText: "There have been multiple AI winters in the history of artificial intelligence.", options: ["True", "False"], correctAnswer: "True", explanation: "The first major AI winter occurred in the 1970s after the Lighthill Report in the UK, and the second struck in the late 1980s when expert systems failed to deliver on promises."),
        Question(id: "aih2_q3", type: .fillInBlank, questionText: "AI winters happen when __________ about AI capabilities exceed what the technology can actually deliver.", options: ["expectations", "budgets", "publications", "patents"], correctAnswer: "expectations", explanation: "When grand promises are not met, disappointment leads to funding cuts. The Lighthill Report of 1973 and the collapse of the Lisp machine market in the late 1980s both followed this pattern."),
        Question(id: "aih2_q4", type: .multipleChoice, questionText: "What triggered the first AI winter in the 1970s?", options: ["The UK's Lighthill Report criticized AI for failing to deliver on ambitious promises", "Neural networks became too expensive to train", "The internet disrupted traditional AI research", "Deep learning algorithms were discovered to be flawed"], correctAnswer: "The UK's Lighthill Report criticized AI for failing to deliver on ambitious promises", explanation: "Sir James Lighthill's 1973 report to the British government concluded that AI had failed to achieve its grand objectives, leading to severe funding cuts across the UK and US."),
        Question(id: "aih2_q5", type: .matchPairs, questionText: "Match AI eras with their defining characteristics:", matchPairs: [
            MatchPair(term: "1956-1974", definition: "Golden age of AI optimism"),
            MatchPair(term: "1974-1980", definition: "First AI winter"),
            MatchPair(term: "1980-1987", definition: "Expert systems boom"),
            MatchPair(term: "1987-1993", definition: "Second AI winter")
        ], explanation: "AI history has cycled between periods of intense optimism and painful disappointment, each driven by the gap between promises and reality."),
        Question(id: "aih2_q6", type: .scenarioJudgment, questionText: "In the 2020s, global AI investment surpassed hundreds of billions of dollars annually. Based on historical patterns, could another AI winter occur?", options: ["Yes, if commercial returns consistently fall short of massive investments", "No, the technology is fundamentally different now", "It depends"], correctAnswer: "Yes, if commercial returns consistently fall short of massive investments", explanation: "While today's AI is far more capable, the historical pattern of hype cycles suggests that unrealistic expectations and disappointing returns could still trigger a correction.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "aih_l3", title: "Deep Learning Revolution", description: "The breakthrough that changed everything", categoryId: "ai_history", questions: [
        Question(id: "aih3_q1", type: .multipleChoice, questionText: "The modern deep learning revolution is often dated to:", options: ["2012, when AlexNet dominated the ImageNet competition", "1997, when Deep Blue beat Kasparov at chess", "2006, when Geoffrey Hinton published on deep belief networks", "2016, when AlphaGo defeated Lee Sedol"], correctAnswer: "2012, when AlexNet dominated the ImageNet competition", explanation: "Alex Krizhevsky's AlexNet, trained on GPUs in Geoffrey Hinton's lab, won ImageNet 2012 by a massive margin, proving that deep neural networks could outperform traditional computer vision."),
        Question(id: "aih3_q2", type: .trueFalse, questionText: "Geoffrey Hinton, Yann LeCun, and Yoshua Bengio are called the 'Godfathers of Deep Learning.'", options: ["True", "False"], correctAnswer: "True", explanation: "These three researchers shared the 2018 Turing Award for their decades of foundational work on neural networks and deep learning, much of which was done when the field was deeply unfashionable."),
        Question(id: "aih3_q3", type: .fillInBlank, questionText: "The __________ dataset, created by Fei-Fei Li and her team at Stanford, was a key catalyst for the deep learning revolution in computer vision.", options: ["ImageNet", "CIFAR", "MNIST", "COCO"], correctAnswer: "ImageNet", explanation: "Fei-Fei Li led the creation of ImageNet, which contained over 14 million labeled images. Its annual challenge drove breakthroughs that proved deep learning's power."),
        Question(id: "aih3_q4", type: .sortOrder, questionText: "Order these deep learning milestones chronologically:", options: ["Transformer architecture introduced (2017)", "AlexNet wins ImageNet (2012)", "AlphaGo beats Lee Sedol (2016)", "GPT-3 demonstrates few-shot learning (2020)"], correctAnswers: ["AlexNet wins ImageNet (2012)", "AlphaGo beats Lee Sedol (2016)", "Transformer architecture introduced (2017)", "GPT-3 demonstrates few-shot learning (2020)"], explanation: "Deep learning progress accelerated dramatically: from image recognition to game mastery to language understanding within a single decade."),
        Question(id: "aih3_q5", type: .multipleChoice, questionText: "What three factors converged to enable the deep learning revolution?", options: ["Big data, powerful GPUs, and improved algorithms", "Quantum computing, blockchain, and 5G networks", "Government mandates, public demand, and media attention", "Open source licenses, venture capital, and social media"], correctAnswer: "Big data, powerful GPUs, and improved algorithms", explanation: "The internet produced massive datasets, NVIDIA GPUs provided parallel computing power, and techniques like dropout and batch normalization made training deep networks practical."),
        Question(id: "aih3_q6", type: .multipleChoice, questionText: "DeepMind's AlphaGo defeating world champion Lee Sedol in 2016 was significant because:", options: ["Go was considered far too complex for AI due to its astronomical number of positions", "Lee Sedol had never lost a professional match before", "It was the first time AI played a board game competitively", "The match demonstrated quantum computing capabilities"], correctAnswer: "Go was considered far too complex for AI due to its astronomical number of positions", explanation: "Go has more possible board positions than atoms in the observable universe. AlphaGo combined deep learning with Monte Carlo tree search, achieving what experts predicted was decades away.")
    ], order: 2, difficulty: .intermediate)
    static let lesson4 = LessonData(id: "aih_l4", title: "The Generative AI Moment", description: "AI goes mainstream", categoryId: "ai_history", questions: [
        Question(id: "aih4_q1", type: .multipleChoice, questionText: "The 'Attention Is All You Need' paper that introduced the Transformer architecture was published by researchers at:", options: ["Google Brain and Google Research in 2017", "OpenAI and Microsoft in 2019", "Meta AI Research in 2020", "DeepMind and Oxford University in 2016"], correctAnswer: "Google Brain and Google Research in 2017", explanation: "Vaswani et al. published the landmark Transformer paper in 2017. This architecture became the foundation for GPT, BERT, Claude, Gemini, and virtually all modern large language models."),
        Question(id: "aih4_q2", type: .trueFalse, questionText: "ChatGPT reached 100 million users faster than any previous consumer application in history.", options: ["True", "False"], correctAnswer: "True", explanation: "ChatGPT reached 100 million monthly active users by January 2023, about two months after its November 2022 launch, surpassing TikTok, Instagram, and every other app in adoption speed."),
        Question(id: "aih4_q3", type: .fillInBlank, questionText: "The launch of ChatGPT, Claude, Gemini, and other AI assistants made generative AI __________ to everyday people worldwide.", options: ["accessible", "threatening", "incomprehensible", "irrelevant"], correctAnswer: "accessible", explanation: "Conversational interfaces removed the technical barrier, allowing anyone who could type a question to interact with powerful AI models, regardless of their technical background."),
        Question(id: "aih4_q4", type: .multipleChoice, questionText: "What effect did ChatGPT's viral success have on the broader AI industry?", options: ["It triggered a global race among tech companies to develop competing AI products", "It caused most companies to abandon their own AI research", "It led to a temporary decline in AI investment", "It had little effect outside of OpenAI"], correctAnswer: "It triggered a global race among tech companies to develop competing AI products", explanation: "Google accelerated Gemini, Anthropic launched Claude, Meta released open-weight LLaMA models, and companies like Mistral in France and Baidu in China intensified their own efforts."),
        Question(id: "aih4_q5", type: .matchPairs, questionText: "Match these AI models or assistants to their developers:", matchPairs: [
            MatchPair(term: "Gemini", definition: "Google DeepMind"),
            MatchPair(term: "Claude", definition: "Anthropic"),
            MatchPair(term: "LLaMA", definition: "Meta"),
            MatchPair(term: "Mistral", definition: "Mistral AI (France)")
        ], explanation: "The generative AI wave produced a diverse ecosystem of models from companies across the US, Europe, and Asia, each taking different approaches to development and openness."),
        Question(id: "aih4_q6", type: .scenarioJudgment, questionText: "Some historians compare the launch of generative AI assistants to the introduction of the iPhone or the World Wide Web. Is this comparison reasonable?", options: ["Yes, each made powerful technology accessible to billions of people", "No, AI assistants are a minor incremental improvement", "It depends"], correctAnswer: "Yes, each made powerful technology accessible to billions of people", explanation: "Like the web and the iPhone, generative AI fundamentally changed how ordinary people interact with technology, lowering barriers and creating entirely new categories of use.")
    ], order: 3, difficulty: .beginner)
    static let lesson5 = LessonData(id: "aih_l5", title: "AI Pioneers", description: "The people who shaped AI", categoryId: "ai_history", questions: [
        Question(id: "aih5_q1", type: .matchPairs, questionText: "Match AI pioneers to their landmark contributions:", matchPairs: [
            MatchPair(term: "Alan Turing", definition: "Foundational theory of computation"),
            MatchPair(term: "Fei-Fei Li", definition: "Created the ImageNet dataset"),
            MatchPair(term: "Yoshua Bengio", definition: "Pioneered neural language models"),
            MatchPair(term: "Yann LeCun", definition: "Invented convolutional neural networks")
        ], explanation: "These pioneers span decades and continents, each making contributions without which modern AI would not exist."),
        Question(id: "aih5_q2", type: .trueFalse, questionText: "Demis Hassabis co-founded DeepMind, which created AlphaGo and AlphaFold.", options: ["True", "False"], correctAnswer: "True", explanation: "Demis Hassabis co-founded DeepMind in 2010. The lab produced AlphaGo, AlphaFold, and numerous other breakthroughs. It was acquired by Google in 2014 and later merged into Google DeepMind."),
        Question(id: "aih5_q3", type: .multipleChoice, questionText: "Timnit Gebru is known for her influential research on:", options: ["Bias in AI systems and the ethical risks of large language models", "Reinforcement learning for game-playing agents", "Transformer architecture optimization", "Autonomous vehicle navigation systems"], correctAnswer: "Bias in AI systems and the ethical risks of large language models", explanation: "Timnit Gebru co-authored the landmark paper on bias in facial recognition and the influential 'Stochastic Parrots' paper examining risks of large language models. She founded the DAIR Institute to advance responsible AI."),
        Question(id: "aih5_q4", type: .fillInBlank, questionText: "Dario and Daniela __________ co-founded Anthropic, the company behind the Claude AI assistant.", options: ["Amodei", "Altman", "Hassabis", "Zuckerberg"], correctAnswer: "Amodei", explanation: "Dario Amodei (CEO) and Daniela Amodei (President) co-founded Anthropic in 2021, focusing on AI safety research and developing the Claude family of models."),
        Question(id: "aih5_q5", type: .multipleChoice, questionText: "Andrew Ng is widely recognized for:", options: ["Making AI education accessible to millions through online courses", "Co-founding DeepMind with Demis Hassabis", "Authoring the original Transformer paper", "Developing the first self-driving car"], correctAnswer: "Making AI education accessible to millions through online courses", explanation: "Andrew Ng co-founded Coursera, led Google Brain, and created deeplearning.ai. His courses have introduced millions worldwide to machine learning and AI."),
        Question(id: "aih5_q6", type: .multipleChoice, questionText: "Why is geographic and demographic diversity among AI researchers important?", options: ["Diverse teams are more likely to identify biases and build AI that serves all populations fairly", "It primarily improves marketing and public relations for AI companies", "Diversity only matters for non-technical roles in AI organizations", "It helps reduce the cost of AI development"], correctAnswer: "Diverse teams are more likely to identify biases and build AI that serves all populations fairly", explanation: "Research shows that homogeneous teams often overlook biases affecting underrepresented groups. Researchers like Timnit Gebru, Joy Buolamwini, and Rediet Abebe have highlighted how diverse perspectives improve AI fairness.")
    ], order: 4, difficulty: .beginner)
    static let lesson6 = LessonData(id: "aih_l6", title: "Key AI Breakthroughs", description: "Moments that changed the field", categoryId: "ai_history", questions: [
        Question(id: "aih6_q1", type: .sortOrder, questionText: "Put these AI breakthroughs in chronological order:", options: ["AlphaGo beats Lee Sedol (2016)", "Deep Blue beats Kasparov (1997)", "AlphaFold solves protein folding (2020)", "IBM Watson wins Jeopardy! (2011)"], correctAnswers: ["Deep Blue beats Kasparov (1997)", "IBM Watson wins Jeopardy! (2011)", "AlphaGo beats Lee Sedol (2016)", "AlphaFold solves protein folding (2020)"], explanation: "These milestones show AI conquering increasingly complex challenges: from brute-force chess to nuanced language to intuitive strategy to scientific discovery."),
        Question(id: "aih6_q2", type: .trueFalse, questionText: "IBM's Deep Blue used deep learning to defeat Garry Kasparov at chess in 1997.", options: ["True", "False"], correctAnswer: "False", explanation: "Deep Blue relied on brute-force search evaluating 200 million positions per second, combined with hand-crafted heuristics. Deep learning was not practical for such tasks until well over a decade later."),
        Question(id: "aih6_q3", type: .multipleChoice, questionText: "Why was DeepMind's AlphaFold considered one of the most impactful AI breakthroughs for science?", options: ["It solved the 50-year-old protein structure prediction problem in biology", "It was the first AI system to pass the Turing Test", "It generated realistic images from text descriptions", "It achieved human-level performance in medical diagnosis"], correctAnswer: "It solved the 50-year-old protein structure prediction problem in biology", explanation: "Predicting how proteins fold into 3D structures had been an unsolved grand challenge since the 1970s. AlphaFold's predictions for over 200 million proteins are accelerating drug discovery and biological research worldwide."),
        Question(id: "aih6_q4", type: .fillInBlank, questionText: "The __________ architecture, introduced in the 2017 paper 'Attention Is All You Need,' is the foundation of nearly all modern large language models.", options: ["Transformer", "Perceptron", "Autoencoder", "Diffusion"], correctAnswer: "Transformer", explanation: "The Transformer's self-attention mechanism enabled models to process entire sequences in parallel. It underpins GPT, Claude, Gemini, LLaMA, Mistral, and virtually every major language model."),
        Question(id: "aih6_q5", type: .multipleChoice, questionText: "What significant capability did multimodal AI models like GPT-4, Claude 3, and Gemini introduce?", options: ["The ability to understand and reason across both text and images", "The ability to physically interact with the real world", "Perfect accuracy in all factual questions", "Self-awareness and consciousness"], correctAnswer: "The ability to understand and reason across both text and images", explanation: "Multimodal models can process text, images, and sometimes audio or video, enabling richer interactions. This represented a major leap from text-only language models."),
        Question(id: "aih6_q6", type: .scenarioJudgment, questionText: "Looking at AI history from the 1950s to today, what pattern best describes how AI progress has unfolded?", options: ["Long periods of incremental research punctuated by sudden paradigm-shifting breakthroughs", "Smooth, steady, linear improvement decade over decade", "Continuous decline with occasional brief revivals", "Entirely random and unpredictable with no discernible pattern"], correctAnswer: "Long periods of incremental research punctuated by sudden paradigm-shifting breakthroughs", explanation: "AI history shows cycles of quiet foundational work followed by sudden breakthroughs, from expert systems to deep learning to the Transformer, each building on years of prior research.")
    ], order: 5, difficulty: .intermediate)
}
